mapper.sql:
SELECT ROW_NUMBER() OVER(ORDER BY A.STD_ID DESC) AS LINE_NO , COUNT(1) OVER() AS TOTAL_CNT , A.STD_ID , NVL(LAG(A.STD_ID) OVER (ORDER BY A.USER_ID ASC), '') AS BEFORE_STD_NO , NVL(LEAD(A.STD_ID) OVER (ORDER BY A.USER_ID ASC), '') AS AFTER_STD_NO , A.ORG_ID , A.USER_ID , (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.USER_ID) AS USER_ID , (CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) END) AS USERNM , (SELECT D.DEPTNM FROM TB_HOME_USER_DEPT_CD D, TB_LMS_USR U WHERE U.USER_ID = A.USER_ID AND D.DEPT_CD = U.DEPT_CD) AS DEPTNM , (SELECT MOBILE_NO FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS MOBILE_NO , (SELECT EMAIL FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS EMAIL , A.SBJCT_ID , A.ATNDLC_STSCD , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.ATNDLC_APLY_DTTM , A.ATNDLC_CNCL_DTTM , A.ATNDLC_CERT_DTTM , A.ATNDLC_FNSH_DTTM , A.ATNDLC_SBJCT_ID , A.FNSH_ID , A.ACQS_CRDTS , A.DOC_RCPTYN , A.DOC_RCPT_NO , A.EMP_ID , A.SCR_EXLNYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , (CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) END) AS MOD_NM , A.MOD_DTTM FROM TB_LMS_ATNDLC_SBJCT A WHERE 1 = 1
AND A.ORG_ID = #{orgId}
AND A.SBJCT_ID = #{crsCreCd}
AND A.SBJCT_ID = 'NONE'
AND A.USER_ID = #{userId}
AND A.STD_ID = #{stdNo}
AND A.ATNDLC_STSCD = #{enrlSts}
AND TO_DATE(A.MOD_DTTM , 'YYYYMMDDHH24MISS') BETWEEN TO_DATE(#{enrlAplcDttm} , 'YYYYMMDDHH24MISS' ) AND TO_DATE(#{enrlCancelDttm} , 'YYYYMMDDHH24MISS' )
AND ( LOWER((SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))) OR LOWER((CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) END) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))) OR LOWER((SELECT DEPTNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue}))) )
AND A.ATNDLC_STSCD = 'S' AND A.AUDITYN = 'N' ORDER BY A.USER_ID

mapper.select:
/* SQL ID : StdDAO.list 설 명 : 학습자 목록 조회 */ SELECT A.STD_ID , A.ORG_ID , A.SBJCT_ID , A.USER_ID , (CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) END) AS USERNM , A.ATNDLC_STSCD , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.ATNDLC_APLY_DTTM , A.ATNDLC_CNCL_DTTM , A.ATNDLC_CERT_DTTM , A.ATNDLC_FNSH_DTTM , A.ATNDLC_SBJCT_ID , A.FNSH_ID , A.ACQS_CRDTS , A.DOC_RCPTYN , A.DOC_RCPT_NO , (SELECT D.DEPTNM FROM TB_HOME_USER_DEPT_CD D, TB_LMS_USR U WHERE D.DEPT_CD = U.DEPT_CD AND U.USER_ID=A.USER_ID) AS DEPTNM , A.RGN_CD , A.EMP_ID , A.SCR_EXLNYN , A.RECV_NOTICE_YN , A.AIS_DATA_LNKGYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_ATNDLC_SBJCT A WHERE A.ATNDLC_STSCD = 'S'
AND A.SBJCT_ID = #{crsCreCd}
ORDER BY A.STD_ID ASC

/*
     SQL ID : StdDAO.listPageing
     설  명 : 학습자 페이지 목록 정보 조회
*/




    SELECT AA.* FROM (



    ) AA
    WHERE AA.stdNo = #{stdNo}

/*
     SQL ID : StdDAO.count
     설  명 : 당과목 학습자 수 조회
*/
SELECT COUNT(*) FROM (

) Z

/* SQL ID : StdDAO.stdList 설 명 : 수강생 목록 */
SELECT
/* 임의순 */ ROW_NUMBER() OVER(ORDER BY DBMS_RANDOM.VALUE) AS LINE_NO
/* 이름순, 기본순 */ ROW_NUMBER() OVER(ORDER BY (CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) END) ASC) AS LINE_NO
/* 학번순 */ ROW_NUMBER() OVER(ORDER BY A.STD_ID ASC) AS LINE_NO
, A.STD_ID , A.ORG_ID , A.USER_ID , (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.USER_ID) AS USER_ID , (CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) END) AS USERNM , (SELECT DEPTNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS DEPTNM , A.SBJCT_ID , A.ATNDLC_STSCD , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.ATNDLC_APLY_DTTM , A.ATNDLC_CNCL_DTTM , A.ATNDLC_CERT_DTTM , A.ATNDLC_FNSH_DTTM , A.ATNDLC_SBJCT_ID , A.FNSH_ID , A.ACQS_CRDTS , A.DOC_RCPTYN , A.DOC_RCPT_NO , A.EMP_ID , A.SCR_EXLNYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM , NVL(A.SCYR, '-') AS SCYR , NVL(TO_CHAR((SELECT AVG_CRDTS FROM TB_LMS_MRK WHERE USER_ID = A.USER_ID)), '-') AS AVG_CRDTS , NVL(( SELECT RISK_GRDCD FROM TB_LMS_LRN_STOP_RISK_IDX WHERE USER_ID = A.USER_ID AND PSTG_YR = C.SBJCT_ID AND PSTG_SMSTR = C.CRS_ID ), '-') AS RISK_GRDCD , A.GDSC_DGRS_CRS_GBNCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'GDSC_DGRS_CRS_GBNCD' AND CD = A.GDSC_DGRS_CRS_GBNCD) AS GRSC_DEGR_CORS_GBN_NM FROM TB_LMS_ATNDLC_SBJCT A JOIN TB_LMS_SBJCT C ON A.SBJCT_ID = C.SBJCT_ID LEFT JOIN TB_LMS_USER_ACNT B ON A.USER_ID = B.USER_ID AND B.ACNT_STSCD = 'U' WHERE 1 = 1
AND A.ORG_ID = #{orgId}
AND A.SBJCT_ID = #{crsCreCd}
AND A.ATNDLC_STSCD = #{enrlSts}
AND TO_DATE(A.MOD_DTTM , 'YYYYMMDDHH24MISS') BETWEEN TO_DATE(#{enrlAplcDttm} , 'YYYYMMDDHH24MISS' ) AND TO_DATE(#{enrlCancelDttm} , 'YYYYMMDDHH24MISS' )
AND ( (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR (CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) END) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR (SELECT DEPTNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USER_ID LIKE FN_LIKE_VAL(LOWER(#{searchValue}))) )
AND A.STD_ID NOT IN
#{item}
AND A.STD_ID IN
#{item}
AND A.ATNDLC_STSCD = 'S' AND A.AUDITYN = 'N' AND B.USER_ID IS NOT NULL
/* 임의순 */ AND ROWNUM = 1
/* 이름순 */ ORDER BY (CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) END) ASC
/* 학번순 */ ORDER BY A.STD_ID ASC

/* SQL ID : StdDAO.selectStd 설 명 : 강의실 학생 조회 */ SELECT A.STD_ID , A.ORG_ID , A.SBJCT_ID , A.USER_ID , A.ATNDLC_STSCD , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.ATNDLC_APLY_DTTM , A.ATNDLC_CNCL_DTTM , A.ATNDLC_CERT_DTTM , A.ATNDLC_FNSH_DTTM , A.ATNDLC_SBJCT_ID , A.FNSH_ID , A.ACQS_CRDTS , A.DOC_RCPTYN , A.DOC_RCPT_NO , B.DEPTNM , A.RGN_CD , A.EMP_ID , A.SCR_EXLNYN , A.RECV_NOTICE_YN , A.AIS_DATA_LNKGYN , A.AUDITYN , A.REATNDLCYN , A.ATNDLC_ABNDYN , B.USERNM , B.MOBILE_NO , B.EMAIL , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM , B.DISABLILITY_YN FROM TB_LMS_ATNDLC_SBJCT A JOIN TB_LMS_USR B ON A.USER_ID = B.USER_ID
AND B.ORG_ID = #{orgId}
JOIN TB_LMS_USER_ACNT C ON A.USER_ID = C.USER_ID AND C.ACNT_STSCD = 'U' WHERE ( A.ATNDLC_STSCD = 'S' OR (A.ATNDLC_STSCD = 'T' AND A.USER_ID = #{userId}) -- 학생화면보기 학생 ) AND A.SBJCT_ID = #{crsCreCd} AND A.USER_ID = #{userId}
AND A.STD_ID = #{stdNo}

mapper.sql:
SELECT ROW_NUMBER() OVER(ORDER BY B.USERNM, A.USER_ID, A.STD_ID) AS LINE_NO , A.STD_ID , A.ORG_ID , A.SBJCT_ID , A.USER_ID , B.USERNM , B.DEPTNM , A.ATNDLC_STSCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'ENRL_STS_CD' AND CD = A.ATNDLC_STSCD) AS ENRL_STS_NM , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.ATNDLC_APLY_DTTM , A.ATNDLC_CNCL_DTTM , A.ATNDLC_CERT_DTTM , A.ATNDLC_FNSH_DTTM , A.ATNDLC_SBJCT_ID , A.FNSH_ID , A.ACQS_CRDTS , A.DOC_RCPTYN , A.DOC_RCPT_NO , A.RGN_CD , A.EMP_ID , A.SCR_EXLNYN , A.RECV_NOTICE_YN , A.AIS_DATA_LNKGYN , A.AUDITYN , A.ATNDLC_ABNDYN , A.REATNDLCYN -- 재수강 , A.GDSC_DGRS_CRS_GBNCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'GDSC_DGRS_CRS_GBNCD' AND CD = A.GDSC_DGRS_CRS_GBNCD) AS GRSC_DEGR_CORS_GBN_NM , B.EMAIL , B.MOBILE_NO , B.DISABLILITY_YN , B.MN_DSBL_CD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'MN_DSBL_CD' AND CD = B.MN_DSBL_CD) AS DISABILITY_CD_NM , B.MN_DSBL_GRDCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'MN_DSBL_GRDCD' AND CD = B.MN_DSBL_GRDCD) AS DISABILITY_LV_NM , D.UNIV_CD , D.UNIV_GBNCD , E.EXAM_SPRT_APLY_ID , E.MID_APPR_STAT , E.MID_ADD_TIME , E.APRV_STSCD , E.ADD_MNTS , NVL(A.SCYR,'-') SCYR , NVL(B.READMI_YY,'-') READMI_YY , NVL(B.ENTR_YY,'-') ENTR_YY , NVL(B.ENTR_HY,'-') ENTR_HY , NVL(B.ENTR_GBN,'-') ENTR_GBN , NVL(B.ENTR_GBN_NM,'-') ENTR_GBN_NM , NVL(( SELECT TO_CHAR(RISK_IDX) FROM TB_LMS_LRN_STOP_RISK_IDX WHERE USER_ID = A.USER_ID AND PSTG_YR = D.SBJCT_ID AND PSTG_SMSTR = D.CRS_ID ), '-') AS RISK_IDX , NVL(( SELECT TO_CHAR(RISK_GRDCD) FROM TB_LMS_LRN_STOP_RISK_IDX WHERE USER_ID = A.USER_ID AND PSTG_YR = D.SBJCT_ID AND PSTG_SMSTR = D.CRS_ID ), '-') AS RISK_GRDCD FROM TB_LMS_ATNDLC_SBJCT A INNER JOIN TB_LMS_USR B ON A.USER_ID = B.USER_ID
AND B.DISABLILITY_YN = 'Y'
INNER JOIN TB_LMS_USER_ACNT C ON A.USER_ID = C.USER_ID AND C.ACNT_STSCD = 'U' JOIN TB_LMS_SBJCT D ON A.SBJCT_ID = D.SBJCT_ID LEFT JOIN TB_LMS_EXAM_SPRT_APLY E ON A.STD_ID = E.STD_ID AND A.SBJCT_ID = E.SBJCT_ID WHERE A.ATNDLC_STSCD NOT IN ('D', 'T')
AND A.SBJCT_ID = #{crsCreCd}
AND A.SBJCT_ID IN
#{item}
AND A.ORG_ID = #{orgId}
AND A.ATNDLC_STSCD = #{enrlSts}
AND A.USER_ID = #{userId}
AND ( LOWER(A.USER_ID) LIKE '%' || LOWER(#{searchValue}) || '%' OR LOWER(B.USERNM) LIKE '%' || LOWER(#{searchValue}) || '%' OR LOWER(B.DEPTNM) LIKE '%' || LOWER(#{searchValue}) || '%' )
AND NVL(A.AUDITYN, 'N') = 'N'
AND B.DISABLILITY_YN = 'Y'
AND A.AUDITYN = 'Y' AND A.ATNDLC_ABNDYN = 'N'
AND A.AUDITYN = 'Y' AND A.ATNDLC_ABNDYN = 'Y'
AND A.REATNDLCYN = 'Y'

