/*
     SQL ID : StdDAO.selectStudentInfo
     설  명 : 수강생 학습현황 > 수강생 정보
 */
SELECT A.*
       , (SELECT PHT_FILE FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS PHT_FILE_BYTE
  FROM (

    AND A.STD_ID = #{stdNo}
  ) A

/* SQL ID : StdDAO.listStdJoinStatus 설 명 : 강의실 학습요소 참여현황 목록 */ SELECT ROW_NUMBER() OVER(ORDER BY C.USERNM, B.USER_ID, B.STD_ID) AS LINE_NO , A.SBJCT_ID , A.SBJCTNM , B.STD_ID , B.SCYR , B.USER_ID , B.GDSC_DGRS_CRS_GBNCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = B.ORG_ID AND CTGRCD = 'GDSC_DGRS_CRS_GBNCD' AND CD = B.GDSC_DGRS_CRS_GBNCD) AS GRSC_DEGR_CORS_GBN_NM , C.USERNM , C.MOBILE_NO , C.EMAIL , C.DEPTNM , (SELECT COUNT(1) -- 과제 FROM TB_LMS_ASMT AA JOIN TB_LMS_ASMNT_CRE_CRS_RLTN BB ON AA.ASMT_ID = BB.ASMT_ID AND BB.DELYN = 'N' LEFT JOIN TB_LMS_ASMT_SBMSN CC ON AA.ASMT_ID = CC.ASMT_ID AND CC.DELYN = 'N' LEFT JOIN TB_LMS_EXAM_BSC DD -- 대체시험 제외 ON DD.EXAM_SBST_REF_ID = AA.ASMT_ID AND DD.DELYN = 'N' WHERE AA.DELYN = 'N' AND BB.SBJCT_ID = A.SBJCT_ID AND CC.STD_ID = B.STD_ID AND ( AA.IND_YN = 'N' OR (AA.IND_YN = 'Y' AND CC.ASMT_SBMSN_ID IS NOT NULL) ) AND DD.EXAM_ID IS NULL
AND AA.ASMNT_OPEN_YN = 'Y' AND FN_DTTM() >= AA.SEND_START_DTTM
) AS ASMNT_CNT , (SELECT COUNT(1) -- 과제 참여 수 FROM TB_LMS_ASMT AA JOIN TB_LMS_ASMNT_CRE_CRS_RLTN BB ON AA.ASMT_ID = BB.ASMT_ID AND BB.DELYN = 'N' LEFT JOIN TB_LMS_ASMT_SBMSN CC ON AA.ASMT_ID = CC.ASMT_ID AND CC.DELYN = 'N' LEFT JOIN TB_LMS_EXAM_BSC DD -- 대체시험 제외 ON DD.EXAM_SBST_REF_ID = AA.ASMT_ID AND DD.DELYN = 'N' WHERE AA.DELYN = 'N' AND BB.SBJCT_ID = A.SBJCT_ID AND CC.STD_ID = B.STD_ID AND ( AA.IND_YN = 'N' OR (AA.IND_YN = 'Y' AND CC.ASMT_SBMSN_ID IS NOT NULL) ) AND DD.EXAM_ID IS NULL
AND AA.ASMNT_OPEN_YN = 'Y' AND FN_DTTM() >= AA.SEND_START_DTTM
AND UPPER(CC.SBMSN_STSCD) IN ('SUBMIT','RE','LATE') ) AS ASMNT_JOIN_CNT , (SELECT COUNT(1) -- 퀴즈 FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_CRE_CRS_RLTN BB ON AA.EXAM_ID = BB.EXAM_ID LEFT JOIN TB_LMS_EXAM_BSC DD -- 대체시험 제외 ON DD.EXAM_SBST_REF_ID = AA.EXAM_ID AND DD.DELYN = 'N' WHERE AA.ORG_ID = B.ORG_ID AND BB.SBJCT_ID = A.SBJCT_ID AND AA.DELYN = 'N' AND AA.USEYN = 'Y' AND AA.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND AA.EXAM_CTGRCD = 'QUIZ' AND AA.TKEXAM_TYCD = 'A' AND DD.EXAM_ID IS NULL AND FN_DTTM() >= AA.EXAM_SDTTM ) AS QUIZ_CNT , (SELECT COUNT(1) -- 퀴즈 참여 수 FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_CRE_CRS_RLTN BB ON AA.EXAM_ID = BB.EXAM_ID AND BB.DELYN = 'N' LEFT JOIN TB_LMS_EXAM_BSC DD -- 대체시험 제외 ON DD.EXAM_SBST_REF_ID = AA.EXAM_ID AND DD.DELYN = 'N' WHERE AA.ORG_ID = B.ORG_ID AND BB.SBJCT_ID = A.SBJCT_ID AND AA.DELYN = 'N' AND AA.USEYN = 'Y' AND AA.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND AA.EXAM_CTGRCD = 'QUIZ' AND AA.TKEXAM_TYCD = 'A' AND DD.EXAM_ID IS NULL
AND FN_DTTM() >= AA.EXAM_SDTTM
AND EXISTS ( SELECT 1 FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = AA.EXAM_ID AND STD_ID = B.STD_ID AND DELYN = 'N' AND STARE_CNT > 0 ) ) AS QUIZ_JOIN_CNT , (SELECT COUNT(1) -- 설문 FROM TB_LMS_SRVY AA JOIN TB_LMS_RESCH_CRE_CRS_RLTN BB ON AA.SRVY_ID = BB.SRVY_ID AND BB.DELYN = 'N' WHERE AA.ORG_ID = B.ORG_ID AND BB.SBJCT_ID = A.SBJCT_ID AND AA.DELYN = 'N' AND AA.USEYN = 'Y' AND AA.SRVY_QSTNS_CMPTNYN = 'Y' AND AA.SRVY_TMPLTYN = 'N'
AND FN_DTTM() >= AA.SRVY_SDTTM
) AS RESCH_CNT , (SELECT COUNT(1) -- 설문 참여 수 FROM TB_LMS_SRVY AA JOIN TB_LMS_RESCH_CRE_CRS_RLTN BB ON AA.SRVY_ID = BB.SRVY_ID AND BB.DELYN = 'N' WHERE AA.ORG_ID = B.ORG_ID AND BB.SBJCT_ID = A.SBJCT_ID AND AA.DELYN = 'N' AND AA.USEYN = 'Y' AND AA.SRVY_QSTNS_CMPTNYN = 'Y' AND AA.SRVY_TMPLTYN = 'N' AND EXISTS ( SELECT 1 FROM TB_LMS_SRVY_PTCP AAA JOIN TB_LMS_SRVY_RSPNS BBB ON AAA.USER_ID = BBB.USER_ID AND AAA.SRVY_ID = BBB.SRVY_ID WHERE AAA.SRVY_ID = AA.SRVY_ID AND AAA.USER_ID = B.USER_ID AND AAA.STD_ID = B.STD_ID )
AND FN_DTTM() >= AA.SRVY_SDTTM
) AS RESCH_JOIN_CNT , (SELECT COUNT(1) -- 토론 FROM TB_LMS_DSCS AA JOIN TB_LMS_FORUM_CRE_CRS_RLTN BB ON AA.DSCS_ID = BB.DSCS_ID AND BB.DELYN = 'N' LEFT JOIN TB_LMS_EXAM_BSC DD -- 대체시험 제외 ON DD.EXAM_SBST_REF_ID = AA.DSCS_ID AND DD.DELYN = 'N' WHERE AA.DELYN = 'N' AND BB.SBJCT_ID = A.SBJCT_ID AND DD.EXAM_ID IS NULL
AND FN_DTTM() >= AA.DSCS_SDTTM
) AS FORUM_CNT , (SELECT COUNT(1) -- 토론 참여 수 FROM TB_LMS_DSCS AA JOIN TB_LMS_FORUM_CRE_CRS_RLTN BB ON AA.DSCS_ID = BB.DSCS_ID AND BB.DELYN = 'N' LEFT JOIN TB_LMS_EXAM_BSC DD ON DD.EXAM_SBST_REF_ID = AA.DSCS_ID AND DD.DELYN = 'N' WHERE AA.DELYN = 'N' AND BB.SBJCT_ID = A.SBJCT_ID AND DD.EXAM_ID IS NULL AND ( EXISTS ( SELECT 1 FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = AA.DSCS_ID AND STD_ID = B.STD_ID AND DELYN = 'N' ) OR EXISTS ( SELECT 1 FROM TB_LMS_DSCS_CMNT WHERE DSCS_ID = AA.DSCS_ID AND STD_ID = B.STD_ID AND DELYN = 'N' ) )
AND FN_DTTM() >= AA.DSCS_SDTTM
) AS FORUM_JOIN_CNT FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID
AND B.ORG_ID = #{orgId}
AND B.STD_ID = #{stdNo}
AND B.ATNDLC_STSCD = 'S'
JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID AND B.ORG_ID = C.ORG_ID JOIN TB_LMS_USER_ACNT D ON B.USER_ID = D.USER_ID AND D.ACNT_STSCD = 'U' WHERE A.SBJCT_ID = #{crsCreCd} AND B.AUDITYN = 'N'
AND ( LOWER(C.USERNM) LIKE '%' || LOWER(#{searchValue}) || '%' OR LOWER(B.USER_ID) LIKE '%' || LOWER(#{searchValue}) || '%' OR LOWER(C.DEPTNM) LIKE '%' || LOWER(#{searchValue}) || '%' )

/* SQL ID : StdDAO.listAttendByLessonSchedule 설 명 : 주차별 학생 출석현황 */ SELECT ROW_NUMBER() OVER(ORDER BY A.USERNM, A.USER_ID, A.STD_ID) AS LINE_NO , A.* , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'ATNDLC_STSCD' AND CD = A.ATNDLC_STSCD) AS STUDY_STATUS_NM FROM ( SELECT A.SBJCT_ID , A.USER_ID , A.USERNM , A.STD_ID , A.DEPT_CD , A.DEPTNM , A.MOBILE_NO , A.EMAIL , B.LCTR_SCHDL_ID , B.LCTR_SCHDL_SEQ , B.LCTR_SCHDLNM , B.LCTR_SYMD , B.LCTR_EYMD , CASE WHEN C.ATNDLC_STSCD = 'STUDY' AND TO_CHAR(SYSDATE, 'YYYYMMDD') > NVL(B.LCTR_RCG_EYMD, B.LCTR_EYMD) THEN 'NOSTUDY' ELSE NVL(C.ATNDLC_STSCD, 'NOSTUDY') END AS ATNDLC_STSCD , C.STUDY_STATUS_CD_BAK , SCYR , ENTR_YY , ENTR_HY , ENTR_GBN , ENTR_GBN_NM FROM ( -- 강의실 학생 SELECT A.SBJCT_ID , B.ORG_ID , B.USER_ID , B.STD_ID , C.DEPT_CD , C.MOBILE_NO , C.EMAIL , C.USERNM , C.DEPTNM , NVL(B.SCYR,'-') AS SCYR , NVL(C.ENTR_YY,'-') AS ENTR_YY , NVL(C.ENTR_HY,'-') AS ENTR_HY , NVL(C.ENTR_GBN,'-') AS ENTR_GBN , NVL(C.ENTR_GBN_NM,'-') AS ENTR_GBN_NM FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.AUDITYN = 'N'
AND B.STD_ID = #{stdNo}
AND B.USER_ID = #{userId}
JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID JOIN TB_LMS_USER_ACNT D ON B.USER_ID = D.USER_ID AND D.ACNT_STSCD = 'U' WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{crsCreCd}
AND ( LOWER(C.USERNM) LIKE '%' || LOWER(#{searchValue}) || '%' OR LOWER(B.USER_ID) LIKE '%' || LOWER(#{searchValue}) || '%' OR LOWER(C.DEPTNM) LIKE '%' || LOWER(#{searchValue}) || '%' )
) A JOIN TB_LMS_SBJCT_LCTR_SCHDL B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' AND B.LCTR_SCHDL_ID = #{lessonScheduleId} LEFT JOIN TB_LMS_LESSON_STUDY_STATE C ON A.USER_ID = C.USER_ID AND A.STD_ID = C.STD_ID AND B.LCTR_SCHDL_ID = C.LCTR_SCHDL_ID ) A

/* SQL ID : StdDAO.listAttend 설 명 : 강의실 출석현황 */ SELECT A.* , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.MAX_ORG_ID AND CTGRCD = 'GDSC_DGRS_CRS_GBNCD' AND CD = A.GDSC_DGRS_CRS_GBNCD) AS GRSC_DEGR_CORS_GBN_NM , ROW_NUMBER() OVER(ORDER BY A.USERNM, A.USER_ID, A.STD_ID) AS LINE_NO FROM ( SELECT A.SBJCT_ID , A.USER_ID , A.STD_ID , MAX(A.SBJCTNM) AS SBJCTNM , MAX(A.DVCLAS_NO) AS DVCLAS_NO , MAX(A.SCYR) AS SCYR , MAX(A.GDSC_DGRS_CRS_GBNCD) AS GDSC_DGRS_CRS_GBNCD
, MAX(A.USERNM) AS USERNM , MAX(A.DEPTNM) AS DEPTNM , MAX(A.MOBILE_NO) AS MOBILE_NO , MAX(A.EMAIL) AS EMAIL , MAX(A.ORG_ID) AS MAX_ORG_ID
, NVL(MAX(CASE WHEN A.LCTR_SCHDL_ID = #{item} THEN A.ATNDLC_STSCD ELSE NULL END), '') AS STU_STT_CD_${item}
FROM ( SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , A.ORG_ID , A.USER_ID , A.STD_ID , A.SCYR , A.GDSC_DGRS_CRS_GBNCD , A.USERNM , A.DEPTNM , A.MOBILE_NO , A.EMAIL , B.LCTR_SCHDL_ID , NVL(C.ATNDLC_STSCD, 'NOSTUDY') AS ATNDLC_STSCD FROM (
SELECT A.SBJCT_ID , A.SBJCTNM , A.DVCLAS_NO , B.ORG_ID , B.USER_ID , B.STD_ID , B.SCYR , B.GDSC_DGRS_CRS_GBNCD , C.USERNM , C.DEPTNM , C.MOBILE_NO , C.EMAIL FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S'
AND B.STD_ID = #{stdNo}
AND B.USER_ID = #{userId}
JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID JOIN TB_LMS_USER_ACNT D ON B.USER_ID = D.USER_ID AND D.ACNT_STSCD = 'U' WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{crsCreCd}
AND B.AUDITYN = 'N'
AND ( LOWER(C.USERNM) LIKE '%' || LOWER(#{searchValue}) || '%' OR LOWER(B.USER_ID) LIKE '%' || LOWER(#{searchValue}) || '%' OR LOWER(C.DEPTNM) LIKE '%' || LOWER(#{searchValue}) || '%' )
) A CROSS JOIN TB_LMS_SBJCT_LCTR_SCHDL B LEFT JOIN TB_LMS_LESSON_STUDY_STATE C ON A.USER_ID = C.USER_ID AND A.STD_ID = C.STD_ID AND B.LCTR_SCHDL_ID = C.LCTR_SCHDL_ID WHERE A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' AND B.LCTR_SCHDL_ID IN (
#{item}
''
) ) A GROUP BY A.SBJCT_ID, A.USER_ID, A.STD_ID ) A
STU_STT_CD_${item} NOT IN ('COMPLETE', 'LATE')

/* SQL ID : StdDAO.noAttendRateByWeek 설 명 : 주차별 미학습자 비율 */ SELECT A.SBJCT_ID
, MAX(CASE WHEN A.LCTR_SCHDL_ID = #{item} THEN LCTR_SCHDL_ID ELSE '' END) AS LESN_SCHD_${item} , MAX(CASE WHEN A.LCTR_SCHDL_ID = #{item} THEN ROUND((NOSTUDY_CNT / STD_CNT) * 100, 2) ELSE NULL END) AS WEEK_RATE_${item}
, ROUND(AVG((NOSTUDY_CNT / STD_CNT) * 100), 2) AS WEEK_AVG FROM ( SELECT A.SBJCT_ID , A.LCTR_SCHDL_ID , COUNT(1) AS STD_CNT , SUM(CASE WHEN A.ATNDLC_STSCD NOT IN('COMPLETE', 'LATE') THEN 1 ELSE 0 END) AS NOSTUDY_CNT FROM ( SELECT A.SBJCT_ID , A.USER_ID , A.STD_ID , B.LCTR_SCHDL_ID , NVL(C.ATNDLC_STSCD, 'NOSTUDY') AS ATNDLC_STSCD FROM (
SELECT A.SBJCT_ID , B.USER_ID , B.STD_ID FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.ORG_ID = #{orgId} JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID AND B.ORG_ID = C.ORG_ID JOIN TB_LMS_USER_ACNT D ON B.USER_ID = D.USER_ID AND D.ACNT_STSCD = 'U' WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{crsCreCd}
AND B.AUDITYN = 'N'
) A CROSS JOIN ( SELECT LCTR_SCHDL_ID FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE LCTR_SCHDL_ID IN (
#{item}
) ) B LEFT JOIN TB_LMS_LESSON_STUDY_STATE C ON A.USER_ID = C.USER_ID AND A.STD_ID = C.STD_ID AND B.LCTR_SCHDL_ID = C.LCTR_SCHDL_ID ) A GROUP BY A.SBJCT_ID, A.LCTR_SCHDL_ID ) A GROUP BY A.SBJCT_ID

/* SQL ID : StdDAO.selectStdLessonProgress 설 명 : 학생 학습 진도율 */ SELECT ROUND(STD_COMPLETE_CNT / LESSON_CNT * 100, 2) AS STD_RATE , ROUND(TOTAL_RATE, 2) AS TOTAL_RATE FROM ( SELECT SUM(CASE WHEN A.ATNDLC_STSCD IN('COMPLETE', 'LATE') AND A.USER_ID = #{userId} AND A.STD_ID = #{stdNo} THEN 1 ELSE 0 END) AS STD_COMPLETE_CNT , COUNT(DISTINCT A.LCTR_SCHDL_ID) AS LESSON_CNT , AVG(CASE WHEN A.ATNDLC_STSCD IN('COMPLETE', 'LATE') THEN 1 ELSE 0 END) * 100 AS TOTAL_RATE FROM ( SELECT A.SBJCT_ID , A.USER_ID , A.STD_ID , B.LCTR_SCHDL_ID , NVL(C.ATNDLC_STSCD, 'NOSTUDY') AS ATNDLC_STSCD FROM (
SELECT A.SBJCT_ID , B.USER_ID , B.STD_ID FROM TB_LMS_SBJCT A JOIN TB_LMS_ATNDLC_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND B.ATNDLC_STSCD = 'S' AND B.ORG_ID = #{orgId} JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID AND B.ORG_ID = C.ORG_ID JOIN TB_LMS_USER_ACNT D ON B.USER_ID = D.USER_ID AND D.ACNT_STSCD = 'U' WHERE A.DELYN = 'N' AND A.SBJCT_ID = #{crsCreCd} ) A CROSS JOIN ( SELECT LCTR_SCHDL_ID FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE LCTR_SCHDL_ID IN (
#{item}
) ) B LEFT JOIN TB_LMS_LESSON_STUDY_STATE C ON A.USER_ID = C.USER_ID AND A.STD_ID = C.STD_ID AND B.LCTR_SCHDL_ID = C.LCTR_SCHDL_ID ) A GROUP BY A.SBJCT_ID ) A

/* SQL ID : StdDAO.listSubmitHistoryQuiz 설 명 : 제출/참여 이력 목록 (퀴즈) */ SELECT -- 퀴즈 A.EXAM_ID , A.EXAM_TTL , A.EXAM_SDTTM , A.EXAM_EDTTM , A.MRK_RFLTYN , A.MRK_OYN , A.QUIZ_PROGRESS -- 응시기록 , A.ACQS_TOT_SCR , A.EVLYN , A.SDTTM , A.EDTTM , A.STARE_STATUS_CD -- 응시기록 상세 , B.STARE_HSTY_SN , B.CNTN_IP , B.FRST_INQ_DTTM , CASE WHEN B.STARE_HSTY_SN IS NOT NULL THEN (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'HSTRY_TYCD' AND CD = B.HSTRY_TYCD) END AS HSTY_TYPE_NM FROM ( SELECT A.EXAM_ID , A.ORG_ID , A.EXAM_TTL , A.EXAM_SDTTM , A.EXAM_EDTTM , A.MRK_RFLTYN , A.MRK_OYN , A.FRST_INQ_DTTM , CASE WHEN FN_DTTM() < A.EXAM_SDTTM THEN 'READY' WHEN FN_DTTM() BETWEEN A.EXAM_SDTTM AND A.EXAM_EDTTM THEN 'PROGRESS' WHEN FN_DTTM() > A.EXAM_EDTTM THEN 'END' ELSE 'READY' END AS QUIZ_PROGRESS , C.STD_ID , CASE WHEN A.MRK_RFLTYN = 'Y' THEN C.ACQS_TOT_SCR ELSE 0 END AS ACQS_TOT_SCR , C.EVLYN , C.SDTTM , C.EDTTM , CASE WHEN NVL(C.SDTTM, '') = '' THEN 'N' -- 미응시 WHEN NVL(C.EDTTM, '') = '' THEN 'T' -- 임시저장 WHEN NVL(C.EDTTM, '') != '' THEN 'C' -- 응시완료 END AS STARE_STATUS_CD FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.SBJCT_ID = #{crsCreCd} LEFT JOIN TB_LMS_EXAM_STARE C ON A.EXAM_ID = C.EXAM_ID AND C.STD_ID = #{stdNo} AND C.DELYN = 'N' WHERE A.ORG_ID = #{orgId} AND A.DELYN = 'N' AND A.USEYN = 'Y' AND A.EXAM_QSTNS_CMPTNYN IN ('Y', 'M') AND A.EXAM_CTGRCD = 'QUIZ' AND A.TKEXAM_TYCD = 'A' -- 대체시험 제외 AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.EXAM_ID ) ) A LEFT JOIN TB_LMS_EXAM_STARE_HSTY B ON A.EXAM_ID = B.EXAM_ID AND A.STD_ID = B.STD_ID AND B.DELYN = 'N'
AND FN_DTTM() >= A.EXAM_SDTTM
ORDER BY A.FRST_INQ_DTTM DESC, B.FRST_INQ_DTTM DESC

/* SQL ID : StdDAO.listSubmitHistoryResch 설 명 : 제출/참여 이력 목록 (설문) */ SELECT A.SRVY_ID , A.SRVY_TTL , A.SRVY_SDTTM , A.RESCH_END_DTTM , A.MRK_RFLTYN , A.MRK_OYN , A.RESCH_PROGRESS , CASE WHEN EXISTS(SELECT 1 FROM TB_LMS_SRVY_RSPNS WHERE USER_ID = B.USER_ID AND SRVY_ID = B.SRVY_ID) THEN 'Y' ELSE 'N' END AS JOIN_YN , B.USER_ID , B.STD_ID , B.EVLYN , B.SCR , B.CNTN_DVC_TYCD , B.CNTN_IP , B.FRST_INQ_DTTM FROM ( SELECT A.SRVY_ID , A.SRVY_TTL , A.SRVY_SDTTM , A.RESCH_END_DTTM , A.MRK_RFLTYN , A.MRK_OYN , A.FRST_INQ_DTTM , CASE WHEN FN_DTTM() < A.SRVY_SDTTM THEN 'READY' WHEN FN_DTTM() BETWEEN A.SRVY_SDTTM AND A.RESCH_END_DTTM THEN 'PROGRESS' WHEN FN_DTTM() > A.RESCH_END_DTTM THEN 'END' ELSE 'READY' END AS RESCH_PROGRESS FROM TB_LMS_SRVY A JOIN TB_LMS_RESCH_CRE_CRS_RLTN B ON A.SRVY_ID = B.SRVY_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} WHERE A.DELYN = 'N' AND A.USEYN = 'Y' AND A.SRVY_QSTNS_CMPTNYN = 'Y' AND A.SRVY_TMPLTYN = 'N' AND A.ORG_ID = #{orgId} ) A LEFT JOIN TB_LMS_SRVY_PTCP B ON A.SRVY_ID = B.SRVY_ID AND B.STD_ID = #{stdNo}
AND FN_DTTM() >= A.SRVY_SDTTM
WHERE 1=1 AND B.USER_ID = (SELECT USER_ID FROM TB_LMS_ATNDLC_SBJCT WHERE STD_ID = #{stdNo}) ORDER BY A.FRST_INQ_DTTM DESC, B.FRST_INQ_DTTM DESC

/* SQL ID : StdDAO.listSubmitHistoryForum 설 명 : 제출/참여 이력 목록 (토론) */ SELECT A.DSCS_ID , A.DSCS_TTL , A.DSCS_SDTTM , A.DSCS_EDTTM , A.MRK_RFLTYN , A.MRK_OYN , A.FORUM_ATCL_CNT , A.FORUM_CMNT_CNT , A.FORUM_PROGRESS , B.STD_ID , B.EVLYN , CASE WHEN A.MRK_RFLTYN = 'Y' THEN B.SCR ELSE 0 END AS SCR , CASE WHEN A.FORUM_ATCL_CNT > 0 OR A.FORUM_CMNT_CNT > 0 THEN 'Y' ELSE 'N' END AS JOIN_YN FROM ( SELECT A.DSCS_ID , A.DSCS_TTL , A.DSCS_SDTTM , A.DSCS_EDTTM , A.MRK_RFLTYN , A.MRK_OYN , A.FRST_INQ_DTTM , (SELECT COUNT(1) FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = A.DSCS_ID AND DELYN = 'N' AND STD_ID = #{stdNo}) AS FORUM_ATCL_CNT , (SELECT COUNT(1) FROM TB_LMS_DSCS_CMNT WHERE DSCS_ID = A.DSCS_ID AND DELYN = 'N' AND STD_ID = #{stdNo}) AS FORUM_CMNT_CNT , CASE WHEN FN_DTTM() < A.DSCS_SDTTM THEN 'READY' WHEN FN_DTTM() BETWEEN A.DSCS_SDTTM AND A.DSCS_EDTTM THEN 'PROGRESS' WHEN FN_DTTM() > A.DSCS_EDTTM THEN 'END' ELSE 'READY' END AS FORUM_PROGRESS FROM TB_LMS_DSCS A JOIN TB_LMS_FORUM_CRE_CRS_RLTN B ON A.DSCS_ID = B.DSCS_ID AND B.DELYN = 'N' AND B.SBJCT_ID = #{crsCreCd} WHERE A.DELYN = 'N' -- 대체시험 제외 AND NOT EXISTS ( SELECT 1 FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = A.DSCS_ID ) ) A LEFT JOIN TB_LMS_DSCS_PTCP B ON A.DSCS_ID = B.DSCS_ID AND B.DELYN = 'N' AND B.STD_ID = #{stdNo}
AND FN_DTTM() >= A.DSCS_SDTTM
ORDER BY A.FRST_INQ_DTTM DESC

/* SQL ID : StdDAO.selectDetail 설 명 : 학습자 상세 정보를 조회한다 */ SELECT A.STD_ID , A.ORG_ID , A.USER_ID , C.USER_ID , B.USERNM , B.DEPTNM , B.MOBILE_NO AS MOBILE , B.EMAIL , A.SBJCT_ID , A.ATNDLC_STSCD , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.ATNDLC_APLY_DTTM , A.ATNDLC_CNCL_DTTM , A.ATNDLC_CERT_DTTM , A.ATNDLC_FNSH_DTTM , A.ATNDLC_SBJCT_ID , A.FNSH_ID , A.ACQS_CRDTS , A.DOC_RCPTYN , A.DOC_RCPT_NO , A.EMP_ID , A.SCR_EXLNYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_ATNDLC_SBJCT A JOIN TB_LMS_USR B ON A.USER_ID = B.USER_ID JOIN TB_LMS_USER_ACNT C ON A.USER_ID = C.USER_ID WHERE 1 = 1
AND A.SBJCT_ID = #{crsCreCd}
AND A.STD_ID = #{stdNo}
AND C.USER_ID = #{userId}

mapper.insert:
/*
     SQL ID : StdDAO.mergeStd
     설  명 : 개설 과목 수강생 수정(머지문)
*/
INSERT INTO TB_LMS_ATNDLC_SBJCT (
       STD_ID
     , ORG_ID
     , SBJCT_ID
     , USER_ID
     , ATNDLC_STSCD
     , RGTR_ID
     , FRST_INQ_DTTM
     , MDFR_ID
     , MOD_DTTM
) VALUES (
       #{stdNo}
     , #{orgId}
     , #{crsCreCd}
     , #{userId}
     , #{enrlSts}
     , #{rgtrId}
     , FN_DTTM()
     , #{mdfrId}
     , FN_DTTM()
)
ON DUPLICATE KEY
UPDATE
  ATNDLC_STSCD = #{enrlSts}
, MDFR_ID = #{mdfrId}
, MOD_DTTM = FN_DTTM()

mapper.update:
/*
     SQL ID : StdDAO.deleteStd
     설  명 : 수강생 상태값 업데이트
*/
UPDATE TB_LMS_ATNDLC
SET ATNDLC_STSCD = 'D'
WHERE ATNDLC_SBJCT_ID = #{crsCreCd}
AND USER_ID IN

    #{item}

mapper.select:
/* SQL ID : StdDAO.listPaging 설 명 : 학습자 정보 조회 */
SELECT ROW_NUMBER() OVER(ORDER BY TLAH.USER_ID DESC) AS LINE_NO , COUNT(1) OVER() AS TOTAL_CNT , TLAH.USER_ID , NVL(LAG(TLAH.USER_ID) OVER (ORDER BY TLAH.USER_ID ASC), '') AS BEFORE_STD_ID , NVL(LEAD(TLAH.USER_ID) OVER (ORDER BY TLAH.USER_ID ASC), '') AS AFTER_STD_ID , TLAS.ORG_ID -- , A.USER_ID , (CASE WHEN TLAH.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = TLAH.USER_ID) END) AS USERNM -- , (SELECT CDNM FROM TB_LMS_CMMN_CD WHERE CD = TLAH.DEPT_CD) AS DEPTNM -- , (SELECT MOBILE_NO FROM TB_LMS_USR WHERE CLUSTER_ID() = TLAH.USER_ID) AS MOBILE -- , (SELECT EMAIL FROM TB_LMS_USR WHERE USER_ID = TLAH.USER_ID) AS EMAIL , TLAH.ATNDLC_SBJCT_ID , TLAH.ATNDLC_STSCD -- , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = TLAH.ORG_ID AND CTGRCD = 'ENRL_STS_CD' AND CD = TLAH.ATNDLC_STSCD) AS ENRL_STS_NM , TLAH.ATNDLC_SDTTM , TLAH.ATNDLC_EDTTM , TLAH.AUDIT_EDTTM , TLAS.ATNDLC_APLY_DTTM , TLAS.ATNDLC_CNCL_DTTM , TLAS.ATNDLC_CERT_DTTM , TLAS.ATNDLC_FNSH_DTTM , TLAS.FNSH_NO , TLAS.ACQS_CRDTS -- , TLAH.DOC_RCPTYN -- , TLAH.DOC_RCPT_NO -- , TLAH.EMP_ID -- , TLAH.SCR_EXLNYN , TLAH.RGTR_ID , (CASE WHEN TLAH.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = TLAH.RGTR_ID) END) AS RGTRNM , TLAH.REG_DTTM , TLAH.MDFR_ID , (CASE WHEN TLAH.MDFR_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = TLAH.MDFR_ID) END) AS MOD_NM , TLAH.MOD_DTTM -- , (SELECT SCHREG_GBN FROM TB_LMS_USER_PRFIL WHERE USER_PRFIL_ID = TLAH.USER_ID) AS SCHREG_GBN FROM TB_LMS_ATNDLC_HSTRY TLAH, TB_LMS_ATNDLC_SBJCT TLAS WHERE TLAH.ATNDLC_SBJCT_ID = TLAS.ATNDLC_SBJCT_ID
AND A.ORG_ID = #{orgId}
AND TLAS.SBJCT_ID = #{crsCreCd}
AND TLAH.ATNDLC_STSCD = #{enrlSts}
AND STR_TO_DATE(A.MOD_DTTM , '%Y%m%d%H%i%s') BETWEEN STR_TO_DATE(#{enrlAplcDttm} , '%Y%m%d%H%i%s' ) AND STR_TO_DATE(#{enrlCancelDttm} , '%Y%m%d%H%i%s' )
AND ( (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR (CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) END) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR (SELECT DEPTNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.STD_ID NOT IN
#{item}
ORDER BY TLAH.USER_ID ASC

/* SQL ID : StdDAO.stdSelect 설 명 : 학습자를 조회한다 */ SELECT A.STD_ID , A.ORG_ID , A.SBJCT_ID , A.USER_ID , (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.USER_ID) AS USER_ID , (CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) END) AS USERNM , (SELECT DEPTNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS DEPTNM , (SELECT MOBILE_NO FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS MOBILE , (SELECT EMAIL FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS EMAIL , A.SBJCT_ID , A.ATNDLC_STSCD , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.ATNDLC_APLY_DTTM , A.ATNDLC_CNCL_DTTM , A.ATNDLC_CERT_DTTM , A.ATNDLC_FNSH_DTTM , A.ATNDLC_SBJCT_ID , A.FNSH_ID , A.ACQS_CRDTS , A.DOC_RCPTYN , A.DOC_RCPT_NO , A.EMP_ID , A.SCR_EXLNYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_ATNDLC_SBJCT A WHERE 1 = 1
AND A.SBJCT_ID = #{crsCreCd}
AND A.USER_ID = #{userId}

/* SQL ID : StdDAO.exList 설 명 : 학습자 상세 정보를 조회 */ SELECT ROW_NUMBER() OVER(ORDER BY A.STD_ID ASC) AS LINE_NO
, A.STD_ID , A.ORG_ID , A.USER_ID , (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.USER_ID) AS USER_ID , (CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) END) AS USERNM , (SELECT DEPTNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS DEPTNM , A.SBJCT_ID , A.ATNDLC_STSCD , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.ATNDLC_APLY_DTTM , A.ATNDLC_CNCL_DTTM , A.ATNDLC_CERT_DTTM , A.ATNDLC_FNSH_DTTM , A.ATNDLC_SBJCT_ID , A.FNSH_ID , A.ACQS_CRDTS , A.DOC_RCPTYN , A.DOC_RCPT_NO , A.EMP_ID , A.SCR_EXLNYN , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM , (SELECT SCHREG_GBN FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) AS SCHREG_GBN FROM TB_LMS_ATNDLC_SBJCT A WHERE 1 = 1
AND A.ORG_ID = #{orgId}
AND A.SBJCT_ID = #{crsCreCd}
AND A.ATNDLC_STSCD = #{enrlSts}
AND STR_TO_DATE(A.MOD_DTTM , '%Y%m%d%H%i%s') BETWEEN STR_TO_DATE(#{enrlAplcDttm} , '%Y%m%d%H%i%s' ) AND STR_TO_DATE(#{enrlCancelDttm} , '%Y%m%d%H%i%s' )
AND ( (SELECT USER_ID FROM TB_LMS_USER_ACNT WHERE USER_ID = A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR (CASE WHEN A.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) END) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR (SELECT DEPTNM FROM TB_LMS_USR WHERE USER_ID = A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )
AND A.STD_ID NOT IN
#{item}
AND A.STD_ID IN
#{item}
AND A.ATNDLC_STSCD NOT IN ('D', 'T') ORDER BY A.STD_ID ASC

/* SQL ID : StdDAO.listCrsCre 설 명 : 강의실 목록 */
SELECT ROW_NUMBER() OVER(ORDER BY A.SBJCTNM, A.DVCLAS_NO) AS LINE_NO , A.SBJCT_ID , A.CRS_ID , A.SBJCTNM , A.SBJCT_ENNM , A.SBJCT_ID , A.CRS_ID , A.DVCLAS_NO , A.SBJCT_EXPLN , A.SBJCT_OP_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = B.ORG_ID AND CTGRCD = 'LEARNING_TYPE' AND CD = A.SBJCT_OP_TYCD) AS CRS_OPER_TYPE_NM , A.DEPT_CD , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE ORG_ID = B.ORG_ID AND DEPT_CD = A.DEPT_CD AND USEYN = 'Y') AS DEPTNM , A.CRDTS , A.CMCRS_GBNCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = B.ORG_ID AND CTGRCD = 'CMCRS_GBNCD' AND CD = A.CMCRS_GBNCD) AS COMP_DV_NM , A.LCTR_TYCD , A.LRN_CNTRL , A.MID_ATNDC_CHK_USEYN , A.DPLM_OTPTYN , A.DPLM_SCRYN , A.FNSH_PROC_TYCD , A.FNSH_SCR , A.FNSH_SCR_DELRT , A.ATNDC_DELRT , A.ASMT_DELRT , A.DSCS_DELRT , A.EXAM_DELRT , A.TEAM_ACTV_DELRT , A.ETC_DELRT , A.ATNDLC_APLY_MTHD_CD , A.QUOTA_LMTYN , A.ATNDLC_QUOTA , A.ATNDLC_CERT_STSCD , A.ATNDLC_APLY_SDTTM , A.ATNDLC_APLY_EDTTM , A.ATNDLC_SDTTM , A.ATNDLC_EDTTM , A.AUDIT_EDTTM , A.MRK_PROC_SDTTM , A.MRK_PROC_EDTTM , A.MRK_OYN , A.MRK_OPEN_SDTTM , A.MRK_INQ_SRVYYN , A.MRK_INQ_SRVY_ID , A.USEYN , A.AIS_DATA_LNKGYN , A.KYWD , A.DELYN , C.USER_ID AS REP_USER_ID , (CASE WHEN C.USER_ID IS NULL THEN '-' ELSE (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = C.USER_ID) END) AS REP_USER_NM , (SELECT CRS_SMSTR_ID FROM TB_LMS_TERM_CRE_CRS_RLTN WHERE SBJCT_ID = A.SBJCT_ID AND ROWNUM = 1) AS CRS_SMSTR_ID , A.UNIV_CD , (SELECT COUNT(1) FROM TB_LMS_ATNDLC_SBJCT WHERE SBJCT_ID = A.SBJCT_ID AND ATNDLC_STSCD = 'S') AS STD_CNT , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_SBJCT A JOIN TB_LMS_CRS B ON A.CRS_ID = B.CRS_ID
AND A.UNIV_CD = #{uniCd}
AND A.UNIV_GBNCD = #{univGbn}
AND B.ORG_ID = #{orgId}
LEFT JOIN SBJCT_PROF C ON A.SBJCT_ID = C.SBJCT_ID AND C.RPRSYN = 'Y' INNER JOIN TB_LMS_TERM_CRE_CRS_RLTN D ON A.SBJCT_ID = D.SBJCT_ID
AND D.CRS_SMSTR_ID = #{termCd}
WHERE A.DELYN = 'N'
AND A.SBJCT_ID = #{creYear}
AND A.SBJCT_ID = #{crsCreCd}
AND A.CRS_ID = #{creTerm}
AND A.DEPT_CD = #{deptCd}
AND B.SBJCT_TYCD IN
#{item}
AND ( LOWER(A.CRS_ID) LIKE '%' || LOWER(#{searchValue}) || '%' OR LOWER(A.SBJCTNM) LIKE '%' || LOWER(#{searchValue}) || '%' OR (CASE WHEN C.USER_ID IS NULL THEN '-' END) LIKE '%' || LOWER(#{searchValue}) || '%' )
ORDER BY A.SBJCTNM ASC
ORDER BY A.SBJCTNM DESC
ORDER BY A.SBJCTNM, A.DVCLAS_NO

