     SQL ID : StdDAO.insertTmpStd
     설  명 : 임시 수강생 등록
 */
INSERT INTO TB_LMS_ATNDLC_SBJCT (
      STD_ID
    , ORG_ID
    , SBJCT_ID
    , USER_ID
    , ATNDLC_STSCD























    , RGTR_ID
    , FRST_INQ_DTTM


)
SELECT
