/* SQL ID : StdDAO.selectStdAll 설 명 : 학기 수강생 전체 조회 */ SELECT S.SBJCT_ID , S.USER_ID , S.ATNDLC_STSCD FROM TB_LMS_ATNDLC_SBJCT S, TB_LMS_SBJCT C, TB_LMS_TERM_CRE_CRS_RLTN R WHERE 1 = 1 AND S.SBJCT_ID = C.SBJCT_ID AND S.SBJCT_ID = R.SBJCT_ID
AND C.SBJCT_ID = #{creYear}
AND C.CRS_ID = #{creTerm}
AND ( LOWER(C.CRS_ID) LIKE CONCAT('%', LOWER(#{searchValue}), '%') OR LOWER(S.USER_ID) LIKE CONCAT('%', LOWER(#{searchValue}), '%') )

mapper.sql:
SELECT ROW_NUMBER() OVER(ORDER BY B.USERNM) + #{firstIndex} AS LINE_NO , A.SBJCT_ID , A.CRS_ID , A.USER_ID , B.USERNM , B.DEPTNM , A.PSTG_YR , A.PSTG_SMSTR , A.RISK_IDX , A.RISK_GRDCD , A.RGTR_ID , A.FRST_INQ_DTTM , A.MDFR_ID , A.MOD_DTTM FROM TB_LMS_LRN_STOP_RISK_IDX A JOIN TB_LMS_USR B ON A.USER_ID = B.USER_ID WHERE PSTG_YR = #{pubYear}
AND PSTG_SMSTR = #{pubTerm}
AND ( LOWER(B.USERNM) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) OR LOWER(A.USER_ID) LIKE FN_LIKE_VAL(LOWER(#{searchValue})) )

