/* SQL ID : StdDAO.listStudentRecord 설 명 : 수강생별 학습기록 수강생 조회 */
SELECT Z.* , CASE WHEN Z.ATNDLC_MNTS / NULLIF(Z.VDO_MNTS,0) > 1 THEN 100 ELSE ROUND((Z.ATNDLC_MNTS / NULLIF(Z.VDO_MNTS,0) * 100)) END AS prgrRatio , COUNT(Z.STD_ID) OVER() AS TOTAL_CNT , ROW_NUMBER() OVER(ORDER BY Z.USERNM) AS LINE_NO FROM ( SELECT (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE ORG_ID = #{orgId} AND DEPT_CD = C.DEPT_CD) AS DEPTNM , C.USER_ID , C.USERNM , A.STD_ID , NVL(A.SCYR, '-') AS SCYR , NVL(C.MOBILE_NO, '-') AS MOBILE_NO , C.EMAIL , NVL(C.SCHREG_GBN, '-') AS SCHREG_GBN , B.SBJCT_ID , B.SBJCTNM , B.DVCLAS_NO , B.SBJCT_TYCD , CASE WHEN B.SBJCT_TYCD = 'LEGAL' THEN NVL(( SELECT NVL((SELECT SUM(STUDY_TOTAL_TM) AS STUDY_TOTAL_TM FROM TB_LMS_LESSON_STUDY_RECORD R, TB_LMS_SBJCT_LCTR_CONTS S, TB_LMS_SBJCT_LCTR_CLASTM T WHERE 1=1 AND R.STD_ID = AA.STD_ID AND R.SBJCT_LCTR_CONTS_ID = S.SBJCT_LCTR_CONTS_ID AND S.LCTR_SCHDL_ID = T.LCTR_SCHDL_ID AND S.SBJCT_LCTR_CLASTM_ID = T.SBJCT_LCTR_CLASTM_ID AND T.LCTR_SCHDL_ID = AA.LCTR_SCHDL_ID ), 0) STUDY_TOTAL_TM FROM TB_LMS_LESSON_STUDY_STATE AA, TB_LMS_SBJCT_LCTR_SCHDL BB WHERE 1=1 AND AA.STD_ID = A.STD_ID AND AA.LCTR_SCHDL_ID = BB.LCTR_SCHDL_ID ), 0) ELSE 0 END AS ATNDLC_MNTS , CASE WHEN B.SBJCT_TYCD = 'LEGAL' THEN NVL((SELECT AA.LCTR_TOC_LRN_SCNDS FROM TB_LMS_SBJCT_LCTR_SCHDL AA WHERE AA.SBJCT_ID = B.SBJCT_ID AND AA.DELYN = 'N' AND AA.LCTR_SCHDL_SEQ = 1), 0) * 60 ELSE 0 END AS VDO_MNTS , CASE WHEN B.SBJCT_TYCD = 'LEGAL' THEN NVL((SELECT ATNDLC_STSCD FROM TB_LMS_LESSON_STUDY_STATE WHERE STD_ID = A.STD_ID), 'NOSTUDY') END AS ATNDLC_STSCD FROM TB_LMS_ATNDLC_SBJCT A JOIN TB_LMS_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID AND A.ATNDLC_STSCD = 'S' AND A.AUDITYN = 'N' AND B.DELYN = 'N' JOIN TB_LMS_USR C ON A.USER_ID = C.USER_ID JOIN TB_LMS_USER_ACNT D ON C.USER_ID = D.USER_ID AND D.ACNT_STSCD = 'U' WHERE A.ORG_ID = #{orgId}
AND B.SBJCT_ID = #{creYear}
AND B.CRS_ID = #{creTerm}
AND C.DEPT_CD = #{deptCd}
AND B.SBJCT_ID = #{crsCreCd}
AND B.SBJCT_TYCD IN
#{item}
AND ( LOWER(C.USER_ID) LIKE '%' || LOWER(#{searchValue}) || '%' OR LOWER(C.USERNM) LIKE '%' || LOWER(#{searchValue}) || '%' )
AND A.STD_ID IN
#{item}
ORDER BY C.USERNM ) Z WHERE 1 = 1
AND Z.ATNDLC_STSCD != 'COMPLETE'
AND Z.ATNDLC_STSCD = 'COMPLETE'

